CREATE TABLE products (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, name TEXT NOT NULL, price NUMERIC NOT NULL, category TEXT NOT NULL, description TEXT, images TEXT[] DEFAULT '{}', code TEXT, stock BOOLEAN DEFAULT TRUE, created_at TIMESTAMPTZ DEFAULT NOW()); CREATE TABLE categories (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, name TEXT UNIQUE NOT NULL); CREATE TABLE staff (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, full_name TEXT NOT NULL, login TEXT UNIQUE NOT NULL, created_at TIMESTAMPTZ DEFAULT NOW());